from typing import List

def max_ribbon_length(ribbons: List[int], k: int) -> int:
    for length in range(max(ribbons), 0, -1):
        total = sum(r // length for r in ribbons)
        if total >= k:
            return length
    return 0

from typing import List

def max_ribbon_length(ribbons: List[int], k: int) -> int:
    lo, hi = 1, max(ribbons)
    result = 0
    while lo <= hi:
        mid = lo + (hi - lo) // 2
        total = sum(r // mid for r in ribbons)
        if total >= k:
            result = mid
            lo = mid + 1
        else:
            hi = mid - 1
    return result
